export function createStory(id) {
  const status = registry.get(id)
  if (!status) return 'missing'
  return status.active ? 'active' : 'idle'
}

const commands = profiles
  .filter((profile) => profile.name !== active)
  .map((profile, index) => ({
    id: `activate-${profile.name}`,
    label: `Activate ${profile.name}`,
    shortcut: index < 3 ? `⌘${index + 1}` : undefined,
    category: 'Profile',
    action: () => activate(profile.name),
  }))

const navigation = [
  { id: 'timeline', label: 'Timeline', shortcut: 'g t' },
  { id: 'settings', label: 'Settings', shortcut: 'g s' }
]

function renderUnit(unit) {
  switch (unit.kind) {
    case 'concept':
      return renderConcept(unit)
    case 'code-walk':
      return renderCodeWalk(unit)
    case 'storyboard':
      return renderStoryboard(unit)
  }
}
